## Implementation 1 — Redis sliding window (per API key)

```java
@Component
@RequiredArgsConstructor
public class RateLimiterService {

    private final RedisTemplate<String, String> redis;
    private final RateLimiterConfig config;

    /**
     * Sliding window rate limiter using Redis sorted set.
     * Returns true if request is allowed, false if rate limited.
     */
    public boolean isAllowed(String apiKey) {
        long now = System.currentTimeMillis();
        long windowStart = now - config.getWindowMs(); // e.g., last 60000ms = 1 min
        String key = "ratelimit:" + apiKey;

        List<Object> results = redis.executePipelined((RedisCallback<Object>) connection -> {
            StringRedisConnection conn = (StringRedisConnection) connection;

            // Remove requests older than the window
            conn.zRemRangeByScore(key, 0, windowStart);

            // Count requests in current window
            conn.zCard(key);

            // Add this request with timestamp as score
            conn.zAdd(key, now, now + ":" + UUID.randomUUID());

            // Set key expiry to window size + buffer
            conn.expire(key, config.getWindowMs() / 1000 + 10);

            return null;
        });

        Long requestCount = (Long) results.get(1); // count BEFORE adding this request
        boolean allowed = requestCount < config.getMaxRequests();

        if (!allowed) {
            log.warn("Rate limit exceeded for API key: {} (count: {})", apiKey, requestCount);
        }
        return allowed;
    }

    public long getRemainingRequests(String apiKey) {
        long windowStart = System.currentTimeMillis() - config.getWindowMs();
        redis.opsForZSet().removeRangeByScore("ratelimit:" + apiKey, 0, windowStart);
        Long count = redis.opsForZSet().zCard("ratelimit:" + apiKey);
        return Math.max(0, config.getMaxRequests() - (count != null ? count : 0));
    }
}
```

### Wire it as a filter

```java
@Component
@RequiredArgsConstructor
public class RateLimitFilter extends OncePerRequestFilter {

    private final RateLimiterService rateLimiter;
    private final RateLimiterConfig config;

    @Override
    protected void doFilterInternal(HttpServletRequest request,
            HttpServletResponse response, FilterChain chain)
            throws ServletException, IOException {

        String apiKey = request.getHeader("X-API-Key");
        if (apiKey == null) {
            response.setStatus(HttpStatus.UNAUTHORIZED.value());
            response.getWriter().write("{\"error\": \"Missing X-API-Key header\"}");
            return;
        }

        if (!rateLimiter.isAllowed(apiKey)) {
            long remaining = rateLimiter.getRemainingRequests(apiKey);

            response.setStatus(HttpStatus.TOO_MANY_REQUESTS.value()); // 429
            response.setHeader("X-RateLimit-Limit",
                String.valueOf(config.getMaxRequests()));
            response.setHeader("X-RateLimit-Remaining", String.valueOf(remaining));
            response.setHeader("Retry-After",
                String.valueOf(config.getWindowMs() / 1000)); // seconds to wait
            response.setContentType("application/json");
            response.getWriter().write(
                "{\"error\": \"Too many requests\", \"retryAfterSeconds\": "
                + config.getWindowMs() / 1000 + "}");
            return;
        }

        // Add rate limit headers to successful responses too
        response.setHeader("X-RateLimit-Limit",
            String.valueOf(config.getMaxRequests()));
        response.setHeader("X-RateLimit-Remaining",
            String.valueOf(rateLimiter.getRemainingRequests(apiKey)));

        chain.doFilter(request, response);
    }
}
```

