## Step 2 — Refresh token endpoint with rotation

```java
@RestController
@RequestMapping("/api/auth")
@RequiredArgsConstructor
public class AuthController {

    private final JwtService jwtService;
    private final UserRepository userRepo;
    private final RedisTemplate<String, String> redis;

    @PostMapping("/refresh")
    public ResponseEntity<TokenResponse> refresh(
            @RequestBody RefreshRequest request) {

        String refreshToken = request.getRefreshToken();

        // 1. Validate token signature and expiry
        Claims claims = jwtService.validateToken(refreshToken, true);
        String jti = claims.getId();
        Long userId = Long.valueOf(claims.getSubject());

        // 2. Check if this refresh token is blacklisted (used or revoked)
        if (Boolean.TRUE.equals(redis.hasKey("blacklist:rt:" + jti))) {
            throw new InvalidTokenException("Refresh token already used or revoked");
        }

        // 3. Load user and verify token version matches
        User user = userRepo.findById(userId).orElseThrow();
        Integer tokenVersion = claims.get("version", Integer.class);
        if (!user.getTokenVersion().equals(tokenVersion)) {
            throw new InvalidTokenException("Token version mismatch — please log in again");
        }

        // 4. ROTATION: Blacklist the used refresh token
        long ttlSeconds = claims.getExpiration().getTime() - System.currentTimeMillis();
        redis.opsForValue().set(
            "blacklist:rt:" + jti,
            "used",
            Math.max(ttlSeconds / 1000, 1),
            TimeUnit.SECONDS);

        // 5. Issue NEW access token and NEW refresh token
        String newAccessToken = jwtService.generateAccessToken(user);
        String newRefreshToken = jwtService.generateRefreshToken(user);

        log.info("Token refreshed for user {} — old RT blacklisted, new RT issued", userId);

        return ResponseEntity.ok(new TokenResponse(newAccessToken, newRefreshToken, 900L));
        // 900 seconds = 15 min access token TTL
    }

    @PostMapping("/logout")
    public ResponseEntity<Void> logout(@RequestBody RefreshRequest request,
                                        @AuthenticationPrincipal UserDetails user) {
        Claims claims = jwtService.validateToken(request.getRefreshToken(), true);
        String jti = claims.getId();
        long ttlSeconds = (claims.getExpiration().getTime() - System.currentTimeMillis()) / 1000;

        // Blacklist refresh token so it can't be used again
        redis.opsForValue().set("blacklist:rt:" + jti, "revoked", ttlSeconds, TimeUnit.SECONDS);
        log.info("User {} logged out — refresh token blacklisted", user.getUsername());

        return ResponseEntity.ok().build();
    }
}
```

